from tensorflow.keras import layers, models, utils, backend
from tensorflow.keras.layers import (
    DepthwiseConv2D,
    Activation,
    BatchNormalization,
    Conv2D,
    Concatenate,
    Dropout,
    UpSampling2D,
    AveragePooling2D,
    Lambda,
)
from segmentation_models.backbones.backbones_factory import Backbones

from psanp.classifiers.tensorflow.rosaline_classifier.settings import Settings


def ASPPBlock(output_stride, depth=256, name=""):
    # Stride must be either 8 or 16
    if output_stride not in [8, 16]:
        raise ValueError("ASSP output_stride must be either 8 or 16.")
    concat_axis = 3 if backend.image_data_format() == "channels_last" else 1

    # Precompute atrous rates
    atrous_rates = [6, 12, 18]
    if output_stride == 8:
        atrous_rates = [2 * rate for rate in atrous_rates]

    def wrapper(input_tensor):
        inputs_size = input_tensor.shape.as_list()[
            1:3
        ]  # as_list fixes issue of Dimension

        # Convovle image at different rates
        x0 = Conv2D(
            depth,
            (1, 1),
            strides=(1, 1),
            padding="same",
            name=name + "_aspp_conv_1x1",
            use_bias=False,
        )(input_tensor)

        # Rate 1
        x1 = DepthwiseConv2D(
            (3, 3),
            dilation_rate=atrous_rates[0],
            padding="same",
            name=name + "_aspp_conv_3x3_1",
            use_bias=False,
        )(input_tensor)
        x1 = Activation("relu")(x1)
        x1 = BatchNormalization()(x1)
        x1 = Conv2D(depth, (1, 1), padding="same", use_bias=False)(x1)
        x1 = Activation("relu")(x1)
        x1 = BatchNormalization()(x1)

        # Rate 2
        x2 = DepthwiseConv2D(
            (3, 3),
            dilation_rate=atrous_rates[1],
            padding="same",
            name=name + "_aspp_conv_3x3_2",
            use_bias=False,
        )(input_tensor)
        x2 = Activation("relu")(x2)
        x2 = BatchNormalization()(x2)
        x2 = Conv2D(depth, (1, 1), padding="same", use_bias=False)(x2)
        x2 = Activation("relu")(x2)
        x2 = BatchNormalization()(x2)

        # Rate 3
        x3 = DepthwiseConv2D(
            (3, 3),
            dilation_rate=atrous_rates[2],
            padding="same",
            name=name + "_aspp_conv_3x3_3",
            use_bias=False,
        )(input_tensor)
        x3 = Activation("relu")(x3)
        x3 = BatchNormalization()(x3)
        x3 = Conv2D(depth, (1, 1), padding="same", use_bias=False)(x3)
        x3 = Activation("relu")(x3)
        x3 = BatchNormalization()(x3)

        # Global average pooling, convolution, and upsampling
        image_level_features = AveragePooling2D(pool_size=inputs_size)(input_tensor)
        image_level_features = Conv2D(
            depth, [1, 1], strides=1, name=name + "_img_level_1x1", use_bias=False
        )(image_level_features)
        image_level_features = UpSampling2D(
            (inputs_size),
            interpolation="bilinear",
            name=name + "_aspp_img_level_upsample",
        )(image_level_features)
        image_level_features = Activation("relu")(image_level_features)
        image_level_features = BatchNormalization()(image_level_features)

        # Concatenation and fully connected
        x = Concatenate(axis=concat_axis, name=name + "_aspp_final_concat")(
            [x0, x1, x2, x3, image_level_features]
        )
        x = Conv2D(
            depth,
            (1, 1),
            strides=(1, 1),
            padding="same",
            name=name + "_aspp_final_1x1",
            use_bias=False,
        )(x)
        x = Activation("relu")(x)
        x = BatchNormalization()(x)
        x = Dropout(rate=0.1)(x)
        return x

    return wrapper


def DeepLabV3PlusDecoderBlock(
    n_classes,
    output_stride,
    output_name,
    depth=256,
    name="",
    activation="softmax",
    refining_head=False,
):
    def wrapper(input_tensor, intermediate_tensor):
        x = ASPPBlock(output_stride, depth=depth, name=name)(input_tensor)

        # Upsample and concatenate with adequate skip connection
        x = UpSampling2D((4, 4), interpolation="bilinear", name=name + "_upsample")(x)
        x_skip = intermediate_tensor
        x_skip = Conv2D(
            128,
            (1, 1),
            strides=(1, 1),
            padding="same",
            name=name + "_upsample_fc",
            use_bias=False,
        )(x_skip)
        x_skip = Activation("relu")(x_skip)
        x_skip = BatchNormalization()(x_skip)

        concat_axis = 3 if backend.image_data_format() == "channels_last" else 1
        x = Concatenate(axis=concat_axis, name=name + "_upsample_concat")([x, x_skip])

        # Convolutions and fully-connected
        if refining_head:
            x = Conv2D(
                64, (3, 3), strides=(1, 1), padding="same", name=name + "_up4_3x3"
            )(x)
            x = Activation("relu")(x)
            x = BatchNormalization()(x)

            # Resize to original shape
            x = UpSampling2D(
                (4, 4), name=name + "_final_upsampling", interpolation="bilinear"
            )(x)
            x = Conv2D(
                32, (3, 3), strides=(1, 1), padding="same", name=name + "_final_3x3"
            )(x)
            x = Activation("relu")(x)
            x = BatchNormalization()(x)
            x = Conv2D(
                n_classes,
                (1, 1),
                strides=(1, 1),
                padding="same",
                name=name + "_final_1x1",
            )(x)
            x = BatchNormalization()(x)
            if activation == "tanh":
                x = Activation(activation, name=name + "_tan_normalization")(x)
                x = Lambda(lambda tensor: (tensor + 1.0) * 0.5, name=output_name)(x)
            else:
                x = Activation(activation, name=output_name)(x)
        else:
            x = Conv2D(
                n_classes,
                (3, 3),
                strides=(1, 1),
                padding="same",
                name=name + "_final_3x3",
            )(x)
            x = Activation("relu")(x)
            x = BatchNormalization()(x)

            # Resize to original shape
            x = UpSampling2D(
                (4, 4), name=name + "_final_upsampling", interpolation="bilinear"
            )(x)
            if activation == "tanh":
                x = Activation(activation, name=name + "_tan_normalization")(x)
                x = Lambda(lambda tensor: (tensor + 1.0) * 0.5, name=output_name)(x)
            else:
                x = Activation(activation, name=output_name)(x)

        return x

    return wrapper


def Network(settings: Settings):
    kwargs = {"backend": backend, "layers": layers, "models": models, "utils": utils}

    # Create backbone
    backbone = Backbones.get_backbone(
        settings.network.backbone,
        input_shape=(
            settings.data.tile_radius_x * 2,
            settings.data.tile_radius_y * 2,
            settings.data.input_channels,
        ),
        weights=None,
        include_top=False,
        **kwargs
    )

    # Keep track of backbones's intermediate feature, and extract skip connections
    encoder_features = Backbones.get_feature_layers(settings.network.backbone, n=4)
    skips = [
        (
            backbone.get_layer(name=i).output
            if isinstance(i, str)
            else backbone.get_layer(index=i).output
        )
        for i in encoder_features
    ]

    # Create decoder (DeeplabV3+)
    _input = backbone.input

    # Use Atrous Spatial Pyramid Pooling
    output_channels = settings.data.output_channels_list
    branches = [None] * len(output_channels)
    if "semantic" in output_channels:
        branches[output_channels.index("semantic")] = DeepLabV3PlusDecoderBlock(
            settings.data.n_classes,
            16,
            "semantic",
            name="semantic_decoder",
            activation="softmax",
            refining_head=settings.network.refining_head,
        )(skips[0], skips[2])
    if "segmentation" in output_channels:
        branches[output_channels.index("segmentation")] = DeepLabV3PlusDecoderBlock(
            1,
            16,
            "segmentation",
            name="segmentation_decoder",
            activation=(settings.network.segmentation_activation or "sigmoid"),
            refining_head=settings.network.refining_head,
        )(skips[0], skips[2])
    if "linear" in output_channels:
        branches[output_channels.index("linear")] = DeepLabV3PlusDecoderBlock(
            1,
            16,
            "linear",
            name="linear_decoder",
            activation=(settings.network.linear_activation or "sigmoid"),
            refining_head=settings.network.refining_head,
        )(skips[0], skips[2])

    # Convert sequence as model
    model = models.Model(inputs=_input, outputs=branches)

    return model
